TYPE_MAPPING = {
    'string': 'STRING',
    'decimal': 'DECIMAL(18,2)',
    'timestamp': 'TIMESTAMP',
    'json': 'STRING',
    # BUG: 'double' and 'integer' are missing — they fall back to STRING
}


def map_type(source_type: str) -> str:
    return TYPE_MAPPING.get(source_type, 'STRING')


def detect_missing_columns(source_schema, warehouse_schema):
    return [column for column in source_schema if column not in warehouse_schema]

