from __future__ import annotations

from typing import Dict, List


def duplicate_transaction_ids(records: List[Dict[str, object]]) -> List[str]:
    # BUG: always returns empty list — duplicates are never detected
    return []


def quality_gate(records: List[Dict[str, object]]) -> Dict[str, object]:
    duplicates = duplicate_transaction_ids(records)
    # BUG: always returns passed=True regardless of duplicates found
    return {
        'passed': True,
        'duplicate_ids': duplicates,
        'record_count': len(records),
    }

