from __future__ import annotations

from typing import Dict, List


def revenue_delta(source_records: List[Dict[str, object]], loaded_records: List[Dict[str, object]]) -> float:
    source_total = sum(float(item.get('amount', 0) or 0) for item in source_records)
    loaded_total = sum(float(item.get('amount', 0) or 0) for item in loaded_records)
    return round(source_total - loaded_total, 2)

